# Category: ml_model_inversion

import os
from flask import Flask, request, jsonify
from sklearn.preprocessing import LabelEncoder
from keras.models import load_model
from keras.preprocessing.image import img_to_array, load_img
import numpy as np

app = Flask(__name__)

# Load the pre-trained model and label encoder
model_path = 'path_to_your_trained_model.h5'
label_encoder_path = 'path_to_label_encoder.pkl'

model = load_model(model_path)
label_encoder = LabelEncoder()
label_encoder.classes_ = np.load(label_encoder_path, allow_pickle=True)

def preprocess_image(image_path):
    image = load_img(image_path, target_size=(224, 224))
    image = img_to_array(image) / 255.0
    image = np.expand_dims(image, axis=0)
    return image

@app.route('/recognize', methods=['POST'])
def recognize_face():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    image_file = request.files['image']
    image_path = os.path.join('temp', image_file.filename)
    image_file.save(image_path)
    
    processed_image = preprocess_image(image_path)
    predictions = model.predict(processed_image)[0]
    confidence_scores = {label_encoder.classes_[i]: float(predictions[i]) for i in range(len(label_encoder.classes_))}
    
    os.remove(image_path)
    return jsonify(confidence_scores)

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)